def gen(rng, size):
    n = max(1, min(size, 50))
    s = ''.join(rng.choice('abc') for _ in range(n))
    plen = rng.randint(1, min(50, n + 5))
    star = rng.randint(0, plen - 1)
    chars = []
    for i in range(plen):
        if i == star:
            chars.append('*')
        else:
            chars.append(rng.choice('abc'))
    p = ''.join(chars)
    return [s, p]

