class Solution:
    def hasMatch(self, s, p):
        star = p.index('*')
        prefix, suffix = p[:star], p[star + 1:]
        n = len(s)
        for i in range(n + 1):
            for j in range(i, n + 1):
                t = s[i:j]
                if len(t) >= len(prefix) + len(suffix) and t.startswith(prefix) and t.endswith(suffix):
                    return True
        return False

