class Solution:
    def hasMatch(self, s, p):
        star = p.index('*')
        prefix, suffix = p[:star], p[star + 1:]
        n = len(s)
        for i in range(n - len(prefix) + 1):
            if s[i:i + len(prefix)] != prefix:
                continue
            start = i + len(prefix)
            for end in range(start + len(suffix), n + 1):
                if s[end - len(suffix):end] == suffix:
                    return True
        return False

