var hasMatch = function(s, p) {
    const star = p.indexOf('*');
    const prefix = p.slice(0, star), suffix = p.slice(star + 1);
    const n = s.length;
    for (let i = 0; i <= n - prefix.length; i++) {
        if (s.slice(i, i + prefix.length) !== prefix) continue;
        const start = i + prefix.length;
        for (let end = start + suffix.length; end <= n; end++) {
            if (s.slice(end - suffix.length, end) === suffix) return true;
        }
    }
    return false;
};
